module RefModule(  
    input clk,  
    input enable,  
    input [23:0] adc_input,  
    output reg [23:0] adc_output  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin  
        if (enable) begin  
            adc_output <= adc_input << 2;  
        end  
    end  
endmodule
